import{_ as e,o as a,c as t,j as r,a as n,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const _=JSON.parse('{"title":"对人宝具","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/通用及综合类/FATE能力组/对人宝具.md","filePath":"4.资源分区/6.技艺及称号/通用及综合类/FATE能力组/对人宝具.md"}'),s={name:"4.资源分区/6.技艺及称号/通用及综合类/FATE能力组/对人宝具.md"};function p(i,b,l,u,h,d){return a(),t("div",null,[...b[0]||(b[0]=[r("h1",{id:"对人宝具",tabindex:"-1"},[n("对人宝具 "),r("a",{class:"header-anchor",href:"#对人宝具","aria-label":'Permalink to "对人宝具"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风023")])])],-1),o('<h1 id="对人宝具-1" tabindex="-1">对人宝具 <a class="header-anchor" href="#对人宝具-1" aria-label="Permalink to &quot;对人宝具&quot;">​</a></h1><p>FATE能力组（对人宝具）<br> 描述：出自型月系列世界观，本能力组为该世界观内从者具有的相关宝具，在购买后主神会将其赋予给轮回者，使轮回者获得具现化对应宝具的能力。<br> ——<br> 若无特殊说明，则下述宝具消耗的能量为任意通用能量。<br> ——<br> 对人宝具：对自己、单个敌人等非常有限的对象给予效果的宝具。库丘林的“穿刺·死棘之枪（Gae Bolg）”、哈桑·萨巴赫的“妄想心音（Zabaniya）”等包含在内。魔力的消费量不多，在一对一的战斗中，效率显着的高。</p><p>风王结界（C）<br> 价格：C+1000<br> 咏唱：移动动作<br> 目标：见下<br> 消耗：6点<br> 持续：一场景<br> 描述：不可视之剑。敌人难以把握剑的攻击范围，虽然简单却可以在白刃战中发挥巨大效果。<br> 此宝具是被强力魔术守护着，而并非剑本体是透明的。缠住剑身的风改变了光的折射率，从而使得剑的形状变得看不见。即使并没有到达真空状态，包裹着剑身的风也是非常致命的，能够增加斩击的破坏力。<br> 效果：<br> 你需要消费一个移动动作启动风王结界。持续期间内，你进行的近战白刃攻击获得【B级先制】效果，造成的伤害提升等同自身传奇风度/点。<br> 持续期间内，你使用的近战白刃攻击触及距离增加自身传奇风度*2米。<br> 【特殊的是，该能力提供的先制效果对于并不依赖视觉进行定位（包括盲视在内）的单位无法生效。】</p><p>护法少女·九头龙鏖杀（Gohoushoujyo Kuzuryuousatsu）（C++）<br> 价格：C+1000<br> 咏唱：整轮动作<br> 距离：见下<br> 目标：单一目标<br> 消耗：2点<br> 描述：通过强韧身躯、运动性能以及天生的柔韧与残虐性交织在一起使出的变化自如的乱打。<br> 具体来说，就是使出令人错以为是瞬间移动的超高速移动后，进行殴打踢踹。射程虽短，但很难回避。甚至能打破神性的佑护进行殴打。<br> 大部分对手会当即死亡。<br> 效果：<br> 你需要消费一个整轮动作进行宝具咏唱，随后立刻释放【护法少女·九头龙鏖杀（Gohoushoujyo Kuzuryuousatsu）】。<br> 这是一次正常的招式冲锋，你需要先进行冲锋移动接近目标，随后进行正常的冲锋攻击，本次攻击具有【接触攻击】特性，获得等同自身【传奇力量】*2点的高速，威猛破防能力。<br> 若在计算目标防御后，该能力提供的高速与威猛仍有剩余，则该能力提供的剩余高速与威猛转为等量攻击检定上的速度加值。</p><p>百合飞散剑之舞蹈（Fleur de Lys）（C）<br> 价格：C+1000<br> 咏唱：标准动作<br> 距离：触及距离<br> 目标：单一目标<br> 消耗：2点<br> 持续：见下<br> 描述：夺去见者神智的华美剑舞。<br> 为达自己目的而迷惑众人的迪昂的生存方式，升华为宝具的结果。<br> 作为法兰西象征的百合花瓣洒落四周，并在其中以精 湛的剑舞以幻惑对手，抓准破绽刺出必杀的剑击，精神攻击+物理攻击的连续技。<br> 物理伤害只有宝具发动时的那一次，但幻惑状态会一直持续下去。魔力的消费也很少，相当实用的宝具。<br> 效果：<br> 你需要消费一个标准动作进行宝具咏唱，随后立刻释放【百合飞散剑之舞蹈（Fleur de Lys）】。<br> 这是一次正常的招式攻击，本次攻击的伤害类型可以选择改为精神伤害。若目标被攻击命中，则需要使用意志豁免对抗伤害出目，失败则陷入C级幻像来源的【幻惑】状态。<br> ——<br> 【幻惑】是一种同来源等级的混乱与支配混合的状态，会使承受该状态的单位无法辨别敌我，随机选择攻击目标，也无法对造成这一状态的来源对象进行攻击，即使是范围攻击也会自动避开。<br> 免疫这一等级混乱的单位可以正常辨别敌我，不需要随机选择攻击目标。免疫这一等级支配的单位可以正常攻击来源对象，随机选择中可以正常随机到来源对象。</p><p>差价升级：百合花开豪华绚烂（Fleur de Lys）（C+）<br> 价格：B+2500<br> 咏唱：标准动作<br> 范围：15+【传奇风度*5】米<br> 目标：敌对目标<br> 消耗：5点<br> 描述：夺去见者神智的华美剑舞·第二式，读音与「百合飞散剑之舞蹈」相同。<br> 为达自己目的而迷惑众人的迪昂的生存方式，升华为宝具的结果。浮现出作为法兰西象征的巨大百合之轮以幻惑敌阵，使之筋力、体力、敏捷数值下降。有时能够令对手一回合间无法行动。<br> 效果：<br> 你需要消费一个标准动作进行宝具咏唱，随后立刻释放【百合花开豪华绚烂（Fleur de Lys）】。<br> 这是一次正常的招式攻击，对以自身为中心，范围内的所有敌对目标进行攻击，目标需要使用意志豁免而非正常防御。若目标被攻击命中，则需要使用意志豁免对抗伤害出目，失败则陷入B级幻像来源的【幻惑】状态。<br> ——<br> 【幻惑】是一种同来源等级的混乱与支配混合的状态，会使承受该状态的单位无法辨别敌我，随机选择攻击目标，也无法对造成这一状态的来源对象进行攻击，即使是范围攻击也会自动避开。<br> 免疫这一等级混乱的单位可以正常辨别敌我，不需要随机选择攻击目标。免疫这一等级支配的单位可以正常攻击来源对象，随机选择中可以正常随机到来源对象。</p><p>穿刺·死棘之枪（Gae Bolg）（B）<br> 价格：B+2000<br> 咏唱：整轮动作<br> 距离：触及距离<br> 目标：单一目标<br> 消耗：6点<br> 描述：逆转因果的魔枪。倒转因果，以必中心脏为前题的“果”决定挥舞长枪攻击的“因”。因为结果已经注定了，一般的防御与回避不论怎么做都毫无意义。<br> 这个效果属于一种诅咒（干涉命运）。因这是能逆转因果的“因果之枪”，除非运气好到能改变命运，否则绝对逃不出这个诅咒的。但是由于原使用者的幸运是E级，所以……<br> 效果：<br> 你需要消费一个整轮动作进行宝具咏唱，随后立刻释放【穿刺·死棘之枪（Gae Bolg）】。<br> 这是正常的招式攻击，你需要先对目标进行一次普通近战攻击（此时不视为攻击，也不会真的造成伤害），目标以意志豁免对抗伤害出目，若失败则陷入B级诅咒/命运来源的【定身】效果，仅持续一轮。<br> 若目标成功被【定身】，则你再进行一次普通近战攻击，本次攻击中加骰提升1级（上限8加骰），并与上述提到的第一次攻击一并正常结算伤害。<br> 若目标没有成功被【定身】，则不仅第一次攻击不会造成伤害，第二次攻击也会自动视为落空。<br> ——<br> 在画面表现上，你先在命运程度上锁定目标，制造出命中心脏的结果，再进行攻击。一旦锁定失败，则攻击也会自然落空（如果你想要更加还原画风，还可以再第一次攻击前让目标进行一次机运骰，只要最终结果大于等于10，穿刺·死棘之枪的攻击将自动落空）。</p><p>多元重奏饱和炮击（Quintett Feuer）（A+）<br> 价格：B+3000<br> 咏唱：标准动作<br> 距离：触及距离<br> 目标：单一目标<br> 消耗：10点<br> 描述：通过将肌肉系统、神经系统、血管系统、淋巴系统被拟似地误认为魔术回路，来提升瞬间输出力量的舍身一击。<br> 游走全身的五种回路奏响的雄壮魔力奔流甚至具备能与星光相匹敌的歼灭力，不知为何是对单体生效的宝具。<br> 效果：<br> 你需要消费一个标准动作进行宝具咏唱，随后立刻释放【多元重奏饱和炮击（Quintett Feuer）】。<br> 这是一次正常的招式攻击，本次攻击具有【湮灭】特性，在攻击前进行一个纯耐力检定（除属性本身外，无法计入任何加值，即使是属性相关检定加值），使这次攻击获得等同检定成功数的额外攻击附加成功。<br> ——<br> 释放【多元重奏饱和炮击（Quintett Feuer）】后，你需要立刻将1点完好生命值转化为韧性，若没有完好生命值，则将两倍于这一完好生命值的严重转为韧性。这是由于全身魔力回路过载带来的负面影响，因此转化是不可避免的，无法进行豁免也无法使用任何伤害吸收，抵消类能力减免这一伤害。</p><p>“女神的微笑”（Smile of Stheno）（B）<br> 价格：B+2000<br> 咏唱：标准动作<br> 目标：单一目标<br> 消耗：6点<br> 持续：见下<br> 描述：掳获勇士之心的女神魅力升华而成之物。愁闷悲苦的视线正是刀刃，摄魂夺魄的耳语正是剧毒。<br> 效果：<br> 你需要消费一个标准动作进行宝具咏唱，随后立刻释放【“女神的微笑”（Smile of Stheno）】。<br> 这是一次正常的招式攻击，本次攻击附带等同伤害出目的魅惑不良点数。目标若被命中，则需要使用意志豁免对抗伤害出目，失败则立刻进入【迷情】状态，持续一场景。此外，本次攻击的伤害类型转为精神伤害。</p><p>天蝎一射（Antares Snipe）（A）<br> 价格：B+2000<br> 咏唱：标准动作<br> 距离：武器射程<br> 目标：单一目标<br> 消耗：8点<br> 描述：化为射手座的喀戎始终瞄准着天蝎这个故事的具现化。能够穿透星辰这种弓兵能到达的究极一击。<br> 在解放真名时即可发射，不是由弓，而是由星辰射出的流星一击。就连以神速著称的阿喀琉斯也无法回避这个宝具。主神提供的版本没有原本的限制。<br> 效果：<br> 你需要消费一个标准动作进行宝具咏唱，随后立刻释放【天蝎一射（Antares Snipe）】。<br> 这是一次正常的招式攻击，你进行一次普通弓箭射击检定，本次攻击额外获得8加骰，附带A级措手不及效果。计算射程时，本次攻击中的武器射程将增加等同【传奇风度】*1的倍率。</p><p>妄想心音（Zabaniya）（C）<br> 价格：A+5000<br> 咏唱：整轮动作<br> 距离：【传奇风度*40】米<br> 目标：单一目标<br> 消耗：14点<br> 持续：一场景<br> 描述：将杀害对象描绘于镜中，再由该反镜存在，用以太[Ether]块，造出与杀害对象分毫不差的“双重存在”。<br> 双重存在，拥有与真货互相共鸣的性质，伤害双重存在的话，真货亦同样地会受伤。这是类感咒术，而且也可以说是极为高级的。藉由抓破以此造出的对象的拟似心脏，对象会在表面上毫无损伤地只有心脏被破坏而死亡。<br> 主神提供的版本弥补了原本的距离缺陷。<br> 效果：<br> 你需要消费一个整轮动作进行宝具咏唱，随后立刻释放【妄想心音（Zabaniya）】。<br> 这次一次正常的招式攻击，你需要对射程内的单一目标进行一次普通近战攻击检定，本次攻击附带【魂牵】与【扼魂】特性，【扼魂】的来源为A级诅咒来源。<br> 只要成功命中，你就可以立刻制造出目标的双重存在（魂牵），并且尝试进行一次抓破对方的心脏的行为。这会使目标需要用强韧豁免对抗上述提及的攻击伤害出目，失败则立刻死亡，这是一个A级诅咒来源的即死效果。<br> ——<br> 若目标成功抵抗即死，则你下一轮可以继续使用整轮动作尝试抓破心脏，等同施展这一宝具，重复进行攻击流程。但如果目标没有正常生理部位（比如集群生物），或者即使心脏破坏也能立刻再生，则该能力的即死对目标无效。<br> ——<br> 该能力的持续时间为双重存在的持续时间，也即魂牵标记本身的存在时间。</p><p>解体圣母(Maria the Ripper)（D～B）<br> 价格：A+4000<br> 咏唱：标准动作<br> 射程：【传奇风度*50】米<br> 目标：单一目标<br> 消耗：6点<br> 描述：通常是四把等级D的小刀，当条件集齐时会被加上“当时伦敦贫民街据说有八万名之多的娼妇们，以生活为由所斩杀扔掉的，连娼妇都成不了的孩子们”的怨念，发挥出凶恶的效果。<br> 条件是以下三个：“时段为夜晚”、“对方是女性(或是雌性)”、“有雾”。当全部条件齐全时使用宝具的话，会把对象身体的内脏马上揪出体外，成为被解剖的尸体。条件未齐全的情况下则只停留在给予单纯的伤害，不过这时候每齐备一个条件，威力也会上涨。<br> 由于此宝具不是以小刀攻击，而是一种诅咒，所以在远距离也可以使用。防御此宝具的效果所需要的不是物理上的防御力，而是对于诅咒的耐性。<br> 效果：<br> 你需要消费一个标准动作进行宝具咏唱，随后立刻释放【解体圣母(Maria the Ripper)】。<br> 这次一次正常的招式攻击，你需要进行正常的近战攻击检定，对射程内的单一目标进行攻击，目标使用强韧检定豁免伤害而非正常流程。<br> 若满足处于夜晚，或攻击目标为女性的条件，则本次攻击获得【幻灭】特性，全部满足则再获得额外4个攻击附加成功。<br> 若在满足前两者的情况下，还处于【有雾】的状态，则目标需要使用强韧检定再进行对于伤害出目的对抗，失败则立刻死亡，这是A级诅咒来源的即死效果。</p><p>灼热龙息·万地融解（kafiloga Allgrí）EX<br> 价格：A+4000<br> 动作：移动动作<br> 目标：自身<br> 消耗：14点<br> 持续：一场景<br> 描述：暂时将形态变化为龙种“法夫纳”的宝具。释放强力的龙之息(Dragon Breath)，给予莫大的伤害。来源于生前变成龙飞翔于天际的宝具。基本上在放射完吐息之后就会恢复原状，但也可以一定时间地维持龙的形态飞行。<br> 效果：<br> 你需要消费一个移动动作进行宝具咏唱，随后立刻释放【灼热龙息·万地融解（kafiloga Allgrí）】。<br> 持续时间内，你的形态将暂时变更为龙种“法夫纳”的形象，种族临时视为【龙种】，具有等同自身基础移动速度的完美机动性飞行能力，在防御上获得等同自身耐力一半的天生防御。<br> ——<br> 持续时间内，你的攻击模式变更为龙炎吐息攻击模式，使原本的检定模式，最大可以对以自身为中心，15+【传奇风度*50】米内所有敌对单位造成火焰能量伤害，目标使用强韧豁免而非正常防御流程，附带等同伤害出目的燃烧不良点数，正常豁免，可叠加。</p><p>唯识·直死之魔眼（Yuishiki Chokushi no Magan）（-）<br> 价格：A+4000<br> 动作：标准动作<br> 距离：触及距离<br> 目标：单一目标<br> 消耗：6点<br> 描述：最大限度睁开直死之魔眼，<br> 切断对象“死之线”的攻击。<br> 哪怕拥有上亿年的寿命，或是从停滞到复活的恢复力，<br> 或是数以百计的生命储备，<br> 由于该能力能暴露“其个体的死亡概念”，<br> 所以依然能付与对象无视不死身特性的致命伤。<br> 世间有难以死亡之命，但无能逃离死亡之命。<br> ——终结对于万物都是共通的。<br> 效果：<br> 你需要消费一个标准动作进行宝具咏唱，随后立刻释放【唯识·直死之魔眼（Yuishiki Chokushi no Magan）】。<br> 这是一次正常招式攻击，你需要进行一次普通攻击检定，本次攻击具有等同自身感知数值一半的攻击加值，加值类型为标准加值。同时附带【幻灭】特性，被击杀的目标如同承受了S级禁止复活效果一样处理。<br> 若目标被成功命中，则需要使用反射检定对抗伤害出目，失败则立刻死亡，这是一个A级命运来源的即死效果。</p><p>无偿无限普遍之爱（The Greatest Hits“Calling Agape”）（EX）<br> 价格：S+8000<br> 动作：标准动作<br> 范围：敏感范围<br> 目标：敌对目标<br> 消耗：无<br> 描述：The Greatest Hits“Calling Agape”<br> Amaneku Mushou no Mugen no Ai，将自己包裹在祈祷之壳内，作为更新、更普遍的“爱”之代言人升天、降临的宝具。Ascension。不是作为爱神阿摩耳，而是成为以之为起源的“天之爱”，用无偿而无限的爱照耀地表的神罚系攻击。怎么看都是对界宝具，但本人坚持这是对人宝具。<br> ——<br> 卡莲所说的『爱』，是无条件、无偿爱全体人类的神之爱。也就是Agape。卡莲曾在『老虎竞技场』使用『能将持有者爱的多少化为武器重量』的晨星锤。由于卡莲爱着全人类，所以锤子的重量可以说与地球重量相同。就是那个的FGO版。另外，无限指的是『爱之光炮』，无偿指的是卡莲「免费送你们吧」的这种慷慨的心情。<br> 效果：<br> 你需要消费一个标准动作进行宝具咏唱，随后立刻释放【无偿无限普遍之爱（The Greatest Hits“Calling Agape”）】。<br> 这是一次正常的招式攻击，你需要进行一次普通攻击检定，对范围内的所有敌对目标进行攻击。<br> 本次攻击获得等同自身决心一半的额外攻击附加成功，具有【湮灭】【扼魂】特性，造成物理钝击/光能能量伤害，需要在购买时选择是哪一种伤害类型。此外，被命中的目标需要使用强韧豁免对抗伤害出目，失败则立刻死亡。<br> ——<br> 该能力所有需要计算来源的部分，来源皆为S级命运来源的效果。</p><hr><p>Copyright ? 2024 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',17)])])}const g=e(s,[["render",p]]);export{_ as __pageData,g as default};
